mapper.insert:
insert into adminlog(adminId, type, operationTime, reserveTime
,comment)
values (#{adminId}, #{type}, #{operationTime}, #{reserveTime}
,
#{comment});

mapper.select:
select *
from adminlog


        and type like concat('%',
        #{type},
        '%'
        )


        and operationTime >=
        #{date_min}


        and operationTime <=
        #{date_max}


        and comment like concat('%',
        #{comment},
        '%'
        )


;
